43	/**
44	 * Estimate win probability based on edge (gap) and model spread.
45	 */
46	function estimateWinProbability(gapF: number, spread: number | null): number {
47	  const absGap = Math.abs(gapF);
48	  const s = spread ?? 999; // treat unknown spread as low confidence
49	
50	  if (absGap >= 5 && s <= 2) return 0.72;
51	  if (absGap >= 3 && s <= 2) return 0.65;
52	  if (absGap >= 3 && s <= 4) return 0.58;
53	  if (absGap >= 2 && s <= 2) return 0.60;
54	  return 0.55;
55	}
